/**
 * Options for transaction commit.
 * 
 * Note: Cancellation is NOT supported during commit to maintain atomic semantics.
 * Use rollback() before commit if you need to cancel.
 */
export interface CommitOptions {
  /** Progress callback for tracking operation execution */
  onProgress?: ProgressCallback;
}

codeSnippets.commitWithProgress:
async commit(options?: CommitOptions): Promise<TransactionResult> {
  this.ensureInTransaction();

  try {
    // Create backup for rollback
    const backupResult = await this.ioManager.createBackup({
      description: 'Transaction backup (auto-created)',
    });
    this.transactionBackup = backupResult.path;

    // Load mutable copy of graph
    const graph = await this.storage.getGraphForMutation();
    const timestamp = new Date().toISOString();
    const total = this.operations.length;

    // Initial progress
    options?.onProgress?.(0, total, 'Starting transaction');

    // Apply all operations
    let operationsExecuted = 0;
    for (const operation of this.operations) {
      this.applyOperation(graph, operation, timestamp);
      operationsExecuted++;

      // Report progress
      options?.onProgress?.(
        operationsExecuted,
        total,
        `Applied ${operation.type.replace('_', ' ').toLowerCase()}`
      );
    }

    // Save the modified graph
    await this.storage.saveGraph(graph);

    // Final progress
    options?.onProgress?.(total, total, 'Transaction committed');

    // ... rest of cleanup ...
  } catch (error) {
    // ... existing error handling ...
  }
}

