describe('commit with progress', () => {
  it('should call onProgress for each operation', async () => {
    const progressCalls: [number, number, string][] = [];

    txManager.begin();
    txManager.createEntity({ name: 'A', entityType: 'test', observations: [] });
    txManager.createEntity({ name: 'B', entityType: 'test', observations: [] });
    txManager.createRelation({ from: 'A', to: 'B', relationType: 'knows' });

    const result = await txManager.commit({
      onProgress: (current, total, message) => {
        progressCalls.push([current, total, message ?? '']);
      }
    });

    expect(result.success).toBe(true);
    expect(progressCalls.length).toBeGreaterThanOrEqual(4); // start + 3 ops + end
    expect(progressCalls[0]).toEqual([0, 3, 'Starting transaction']);
    expect(progressCalls[progressCalls.length - 1][2]).toContain('committed');
  });
});
